/* Gedeelde dataset voor "Hoofdzaak of detail?" — 100 teksten (50 hoofdzaak, 50 detail).
   Elke item: { id, onderwerp, zinnen[], highlightedIndex, correctLabel, uitleg } */
window.HZD_ITEMS = [
  {id:1, onderwerp:"school", zinnen:["In de klas begonnen we met een nieuw project over samenwerken.","We maakten groepjes en iedereen kreeg een rol, zoals schrijver of tijdwaakhond.","De meester legde uit dat je beter leert als je ook naar ideeën van anderen luistert.","Soms is het lastig om om de beurt te praten, maar afspraken helpen.","Daarna oefenden we met een opdracht: een brug bouwen van papier.","Eén groep ontdekte dat een driehoekige vorm veel steviger is dan een rechte strook.","We moesten na afloop vertellen wat goed ging en wat beter kon.","Sommige kinderen vonden het fijn dat iedereen evenveel mocht zeggen.","Samenwerken vraagt oefening, maar je komt verder samen.","Volgende week gebruiken we dezelfde aanpak bij een rekenopdracht."], highlightedIndex:8, correctLabel:"hoofdzaak", uitleg:"Deze zin vat de belangrijkste boodschap samen."},
  {id:2, onderwerp:"sport", zinnen:["Sara wilde sneller worden met hardlopen.","Ze begon met drie keer per week trainen in het park.","Eerst liep ze te hard van start en was ze na vijf minuten moe.","Daarom maakte ze een plan: rustig beginnen en later versnellen.","Ze zette een timer op haar horloge om het tempo bij te houden.","Na twee weken merkte ze dat ze langer kon doorrennen zonder te stoppen.","Op zaterdag liep ze zelfs een rondje van twee kilometer.","Haar vriendinnen juichten toen ze de finish haalde.","Door slim te oefenen werd Sara stap voor stap sneller.","Ze besloot haar plan nog een maand vol te houden."], highlightedIndex:6, correctLabel:"detail", uitleg:"Het is een concreet voorbeeld met een specifiek getal."},
  {id:3, onderwerp:"natuur", zinnen:["In het bos kun je veel kleine dieren tegenkomen.","Soms zie je een mierenspoor dat precies dezelfde route volgt.","Mieren werken samen om eten naar het nest te dragen.","Ze gebruiken geursporen om elkaar de weg te wijzen.","Daardoor vinden ze sneller de beste plek met voedsel.","Een mier kan iets tillen dat zwaarder is dan zichzelf.","Als het regent, kruipen ze dieper het nest in.","Zo blijven ze warm en droog.","Mieren zijn echte teamwerkers in de natuur.","Daarom zijn ze interessant om goed te observeren."], highlightedIndex:8, correctLabel:"hoofdzaak", uitleg:"Dit is de overkoepelende conclusie over mieren."},
  {id:4, onderwerp:"techniek", zinnen:["Op school kregen we les over duurzame energie.","We bekeken hoe zonnepanelen zonlicht omzetten in stroom.","De juf liet een klein paneeltje zien dat een lampje liet branden.","Daarna praatten we over windmolens en waterkracht.","We leerden dat je met duurzame energie minder olie en gas nodig hebt.","Sommige daken in onze wijk hebben al panelen liggen.","Bij harde wind kunnen molens extra veel elektriciteit maken.","Toch moet je ook goed nadenken waar je ze neerzet.","Duurzame energie helpt om het milieu minder te belasten.","Aan het einde mochten we een mini-windmolen knutselen."], highlightedIndex:2, correctLabel:"detail", uitleg:"Het paneeltje met lampje is een voorbeeld binnen het onderwerp."},
  {id:5, onderwerp:"dieren", zinnen:["Een egel lijkt soms langzaam, maar hij is best handig.","Overdag slaapt hij vaak onder bladeren of in een holletje.","In de schemering gaat hij op zoek naar eten, zoals slakken en insecten.","Hij heeft een goede neus om voedsel te vinden.","Als hij gevaar hoort, rolt hij zich op tot een stekelige bal.","Dan is hij lastig te pakken voor een roofdier.","In de winter houdt hij een soort winterslaap om energie te sparen.","Daarom is het goed om de tuin niet te netjes te maken.","Met rommelhoekjes help je egels aan schuilplekken.","Zo kunnen ze veilig leven dichtbij mensen."], highlightedIndex:4, correctLabel:"detail", uitleg:"Dit is een specifieke eigenschap, niet de hoofdboodschap."},
  {id:6, onderwerp:"geschiedenis", zinnen:["Lang geleden leefden mensen zonder elektriciteit.","Ze gebruikten kaarsen en olielampen om licht te maken.","In de winter was het binnen vaak koud en donker.","Toch bedachten mensen slimme manieren om het gezellig te maken.","Ze vertelden verhalen bij het vuur en speelden spelletjes.","Soms kwamen buren langs om samen te eten.","In sommige dorpen werd elke avond hetzelfde lied gezongen.","Zo voelde iedereen zich meer verbonden.","Mensen vonden manieren om met weinig comfort toch fijn te leven.","Daarom is het interessant om te vergelijken met nu."], highlightedIndex:8, correctLabel:"hoofdzaak", uitleg:"Deze zin beschrijft het algemene punt van de tekst."},
  {id:7, onderwerp:"gezondheid", zinnen:["In de pauze drinken veel kinderen te weinig water.","Soms merk je dat je minder goed kunt opletten als je dorst hebt.","Water helpt je lichaam om goed te werken.","Ook bij gym en buitenspelen verlies je vocht.","Daarom is het slim om een fles mee te nemen naar school.","De meester zei dat kleine slokjes beter zijn dan alles in één keer.","Op dinsdag was het extra warm op het plein.","Toen kregen een paar kinderen hoofdpijn.","Genoeg drinken helpt je om fit te blijven tijdens de dag.","Dat is een eenvoudige gewoonte met veel effect."], highlightedIndex:6, correctLabel:"detail", uitleg:"Dit gaat over één specifieke dag en situatie."},
  {id:8, onderwerp:"taal", zinnen:["Bij begrijpend lezen zoek je naar wat een tekst echt wil zeggen.","Sommige zinnen geven voorbeelden, maar zeggen niet waar het hele stuk over gaat.","Je kunt jezelf afvragen: waar draait het om?","Soms helpt het om na elke alinea één zin samen te vatten.","Dan ontdek je sneller de hoofdgedachte.","Details herken je vaak aan getallen of namen.","Een detail kan interessant zijn, maar is niet altijd nodig om het verhaal te snappen.","Je kiest de hoofdzaak door naar het grote plaatje te kijken.","Met oefenen wordt het makkelijker om hoofdzaak en detail te onderscheiden.","Daarom trainen we dit vaak in de klas."], highlightedIndex:8, correctLabel:"hoofdzaak", uitleg:"Dit is de algemene conclusie van de uitleg."},
  {id:9, onderwerp:"natuur", zinnen:["In de lente verandert er veel in een vijver.","Kikkers leggen dan eitjes in het water.","Die eitjes lijken op doorzichtige klontjes met een zwart stipje.","Na een tijdje komen er kikkervisjes uit.","Ze hebben eerst kieuwen en zwemmen met een staart.","Later groeien er pootjes en verdwijnt de staart langzaam.","Zo wordt een kikkervisje uiteindelijk een kikker.","In onze schoolvijver zagen we er vorige week wel twintig.","De vijver is een plek waar je groei van dieren goed kunt zien.","Daarom is het leuk om er regelmatig te gaan kijken."], highlightedIndex:7, correctLabel:"detail", uitleg:"Het aantal en de plek zijn extra, specifieke informatie."},
  {id:10, onderwerp:"techniek", zinnen:["Een fiets werkt met eenvoudige techniek.","Als je trapt, draaien de tandwielen mee.","De ketting zorgt dat het achterwiel gaat draaien.","Daardoor kom je vooruit zonder motor.","Met versnellingen kun je makkelijker heuvelop fietsen.","In een hoge versnelling ga je sneller met dezelfde trap.","De remmen zorgen dat je veilig kunt stoppen.","Bij regen moet je vaak iets eerder remmen.","Een fiets gebruikt slimme onderdelen die samenwerken.","Zo kun je met je eigen kracht grote afstanden afleggen."], highlightedIndex:8, correctLabel:"hoofdzaak", uitleg:"Deze zin vat samen waar de tekst over gaat."},
  {id:11, onderwerp:"dieren", zinnen:["Honden kunnen goed leren als je duidelijk bent.","Een hond snapt sneller wat je bedoelt als je hetzelfde woord gebruikt.","Belonen werkt vaak beter dan straffen.","Als je rustig blijft, wordt de hond meestal ook rustiger.","Oefenen in kleine stapjes helpt bij nieuwe trucjes.","Dan blijft het voor de hond leuk en haalbaar.","Sommige honden vinden apporteren geweldig.","Een labrador kan soms tien keer achter elkaar een bal terugbrengen.","Duidelijke training maakt het samenleven met een hond fijner.","Daarom volgen veel baasjes een cursus."], highlightedIndex:7, correctLabel:"detail", uitleg:"Dit is een specifiek voorbeeld met een getal."},
  {id:12, onderwerp:"museum", zinnen:["Onze klas ging op excursie naar een museum.","We kregen een rondleiding langs oude voorwerpen.","De gids vertelde hoe mensen vroeger kookten zonder fornuis.","We mochten ruiken aan kruiden die ze toen gebruikten.","In een zaal stond een kaart van Nederland van honderd jaar geleden.","Daarop zag je dat sommige steden nog veel kleiner waren.","We maakten aantekeningen voor een werkstuk.","Aan het einde moesten we één nieuwe vraag bedenken.","De excursie hielp ons om geschiedenis beter te begrijpen.","Daardoor onthoud je de stof vaak langer."], highlightedIndex:8, correctLabel:"hoofdzaak", uitleg:"Dit beschrijft het belangrijkste effect van de excursie."},
  {id:13, onderwerp:"sport", zinnen:["Bij basketbal is samenwerken net zo belangrijk als scoren.","Als je alleen maar dribbelt, verlies je vaak de bal.","Een goede pass kan een teamgenoot vrij maken.","Dan kan die makkelijker een punt maken.","In de gymles oefenden we met passen en vrijlopen.","De meester telde tot drie voordat je moest passen.","Daardoor keek iedereen sneller om zich heen.","In het laatste potje wonnen we met 12-8.","Samen spelen zorgt dat je als team sterker wordt.","Dat merkten we direct in de wedstrijd."], highlightedIndex:7, correctLabel:"detail", uitleg:"De uitslag is een detail en niet de kern."},
  {id:14, onderwerp:"media", zinnen:["Niet alles wat je online ziet is meteen waar.","Soms maken mensen een titel expres extra spannend.","Dan helpt het om te kijken wie het bericht heeft gemaakt.","Je kunt ook controleren of andere websites hetzelfde melden.","Als iets te mooi klinkt om waar te zijn, is dat vaak een waarschuwing.","Een foto kan bewerkt zijn of uit een andere tijd komen.","Kritisch lezen is daarom belangrijk.","Je hoeft niet alles meteen door te sturen.","Met betrouwbare informatie kun je betere keuzes maken.","Dat is handig op school én daarbuiten."], highlightedIndex:8, correctLabel:"hoofdzaak", uitleg:"Dit is de belangrijkste conclusie van de tekst."},
  {id:15, onderwerp:"weer", zinnen:["Bij onweer zie je vaak eerst bliksem en hoor je later donder.","Dat komt omdat licht sneller is dan geluid.","Je kunt de afstand schatten door te tellen tussen flits en knal.","Bij drie seconden is het onweer ongeveer één kilometer weg.","Soms ruik je na een bui een frisse geur in de lucht.","Bij onweer kun je beter niet onder een boom schuilen.","Ook zwemmen in open water is dan gevaarlijk.","Ga liever naar binnen of zoek een veilig gebouw.","Onweer is indrukwekkend, maar je kunt er verstandig mee omgaan.","Dan blijf je veilig als het weer omslaat."], highlightedIndex:3, correctLabel:"detail", uitleg:"De afstandsregel is specifieke detailinformatie."},
  {id:16, onderwerp:"programmeren", zinnen:["Een computer doet precies wat jij hem opdraagt.","Daarom is een duidelijke instructie belangrijk.","Als je een foutje typt, kan een programma onverwacht reageren.","Programmeren is vaak testen en verbeteren.","Je kijkt wat er gebeurt en past daarna iets aan.","Soms helpt het om één stap tegelijk te veranderen.","In de les maakten we een spelletje met een scoreteller.","De teller ging omhoog als je op een knop klikte.","Met stap voor stap werken los je problemen sneller op.","Zo leer je programmeren zonder boos te worden."], highlightedIndex:1, correctLabel:"hoofdzaak", uitleg:"Dit is een algemene kernzin over programmeren."},
  {id:17, onderwerp:"middeleeuwen", zinnen:["In de middeleeuwen waren markten heel belangrijk.","Mensen kochten er eten, kleding en gereedschap.","Sommige handelaren reisden dagenlang met karren.","Op de markt hoorde je veel talen door elkaar.","Ook werden er verhalen verteld en muziek gemaakt.","Soms kwam er zelfs een goochelaar optreden.","Je hoorde er nieuws dat nog niet in een krant stond.","Daardoor was de markt een plek voor handel én ontmoetingen.","In Utrecht waren er meerdere marktdagen per week.","Zo bleef de stad levendig."], highlightedIndex:8, correctLabel:"detail", uitleg:"Plaats en frequentie zijn extra informatie."},
  {id:18, onderwerp:"bijen", zinnen:["In een bijenvolk heeft elke bij een taak.","De koningin legt eitjes zodat het volk kan groeien.","Werkbijen zoeken nectar en maken daar honing van.","Andere bijen bewaken de ingang van de korf.","Ze gebruiken een dans om te laten zien waar bloemen zijn.","Die dans vertelt ook hoe ver de bloemen ongeveer staan.","Zo werkt het hele volk als één team.","In onze tuin zat een bij op een paarse lavendelbloem.","Bijen zijn belangrijk omdat ze bloemen en fruit bestuiven.","Daarom moeten we ze goed beschermen."], highlightedIndex:8, correctLabel:"hoofdzaak", uitleg:"Dit is de overkoepelende boodschap over bijen."},
  {id:19, onderwerp:"toetsen", zinnen:["Tijdens een toets kun je zenuwachtig worden.","Sommige kinderen krijgen dan ineens een leeg hoofd.","Rustig ademen kan helpen.","Ook helpt het om eerst de makkelijke vragen te maken.","Dan kom je op gang en wordt het minder spannend.","Het is slim om je tijd te verdelen.","Je kunt na tien minuten even checken waar je bent.","In onze klas leggen we potloden neer als we klaar zijn.","Met een goede aanpak kun je toetsen rustiger maken.","Daardoor laat je beter zien wat je kunt."], highlightedIndex:7, correctLabel:"detail", uitleg:"Dit is een klasafspraak; niet de kern."},
  {id:20, onderwerp:"bruggen", zinnen:["Een brug moet stevig zijn zodat hij mensen kan dragen.","Ingenieurs testen daarom eerst met modellen.","Ze kijken welke vorm het meeste gewicht aankan.","Een boog kan krachten goed verdelen.","Ook kabels kunnen een brug sterk maken.","Bij een hangbrug trekken kabels aan hoge torens.","In Rotterdam staat een brug met een grote witte pyloon.","Die brug heet de Erasmusbrug.","Bruggen worden gebouwd met slimme vormen en materialen.","Zo kunnen ze lang meegaan en veel verkeer dragen."], highlightedIndex:7, correctLabel:"detail", uitleg:"De naam van één brug is een voorbeeld."},
  {id:21, onderwerp:"ruimte", zinnen:["De maan lijkt elke nacht hetzelfde, maar dat klopt niet.","Soms zie je een dun sikkeltje en soms een ronde schijf.","Dat komt doordat de maan om de aarde draait.","De zon verlicht steeds een ander deel van de maan.","Die verandering noemen we maanfasen.","Na ongeveer een maand begint de cyclus opnieuw.","Een volle maan kan extra helder lijken in een heldere lucht.","In de winter zie je de maan soms al vroeg op de avond.","Maanfasen laten zien hoe beweging in de ruimte werkt.","Daarom leren we dit bij natuur en techniek."], highlightedIndex:8, correctLabel:"hoofdzaak", uitleg:"Deze zin vat het algemene idee samen."},
  {id:22, onderwerp:"verhaal", zinnen:["Milan vond een oude sleutel op het schoolplein.","Hij stopte hem snel in zijn jaszak en keek om zich heen.","Niemand leek het te zien, behalve Noor die glimlachte.","Na school liepen ze samen naar de fietsenstalling.","Achter een losse plank zat een klein deurtje verstopt.","De sleutel paste precies en het slot klikte open.","Binnen lag een stoffige doos met stickers en een briefje.","Op het briefje stond alleen: 'Durf jij te zoeken?'","Milan en Noor besloten samen het mysterie te ontrafelen.","Ze spraken af om morgen een plan te maken."], highlightedIndex:6, correctLabel:"detail", uitleg:"De doos is een concreet onderdeel van het verhaal."},
  {id:23, onderwerp:"eten", zinnen:["Sommige kinderen slaan hun ontbijt over, maar dat is niet zo slim.","Ontbijten geeft je energie om te leren.","Je brein werkt beter als je iets hebt gegeten.","Een ontbijt hoeft niet groot te zijn.","Een boterham, yoghurt of fruit kan al helpen.","Als je ontbijt, heb je vaak minder snel zin in snoep.","In onze klas nam iemand een banaan en een glas melk mee.","Daarna zei hij dat hij zich rustiger voelde in de les.","Ontbijten helpt je om je dag goed te starten.","Daarom is het een handige gewoonte."], highlightedIndex:8, correctLabel:"hoofdzaak", uitleg:"Dit is de kern van de tekst."},
  {id:24, onderwerp:"muziek", zinnen:["In een orkest spelen veel instrumenten samen.","Sommige instrumenten maken hoge tonen en andere lage.","De dirigent zorgt dat iedereen tegelijk begint en stopt.","Als één groep te hard speelt, hoor je de rest minder goed.","Daarom luisteren muzikanten steeds naar elkaar.","Een orkest kan heel zacht beginnen en daarna steeds harder worden.","Dat heet een crescendo.","Bij ons op school gebruikten we bekers en tafels als instrumenten.","Muziek klinkt het mooist als iedereen goed samenwerkt.","Dan wordt het één geheel in plaats van losse geluiden."], highlightedIndex:6, correctLabel:"detail", uitleg:"‘Crescendo’ is een specifiek begrip."},
  {id:25, onderwerp:"sport", zinnen:["Een warming-up voorkomt niet alle blessures, maar helpt wel.","Je maakt je spieren warmer en soepeler.","Daardoor kun je beter bewegen.","Een goede warming-up bouwt langzaam op.","Eerst rustig lopen, daarna pas sneller.","Ook kun je je armen en benen losmaken met draaien.","Bij voetbal doen veel teams ook korte sprintjes.","Daarna voelt het rennen minder zwaar.","Een warming-up bereidt je lichaam voor op inspanning.","Daarom beginnen sportlessen vaak met opwarmen."], highlightedIndex:8, correctLabel:"hoofdzaak", uitleg:"Dit is de overkoepelende boodschap."},
  {id:26, onderwerp:"bibliotheek", zinnen:["Sophie ging naar de bibliotheek om een spannend boek te zoeken.","Ze wilde iets met een mysterie en een slimme hoofdpersoon.","Bij de kast met jeugdboeken zag ze een boek met een gouden kompas op de kaft.","Ze pakte het eruit en bladerde naar de eerste bladzijde.","Daar stond een zin die meteen nieuwsgierig maakte.","Sophie ging op een zitzak zitten en begon te lezen.","Na vijf minuten was ze al vergeten hoe laat het was.","De bibliotheek was stil, behalve het zachte omslaan van pagina’s.","Een goed boek kan je helemaal meenemen in een andere wereld.","Daarom komt Sophie er graag terug."], highlightedIndex:2, correctLabel:"detail", uitleg:"Het kompas op de kaft is een detail."},
  {id:27, onderwerp:"aardrijkskunde", zinnen:["Rivieren vormen het landschap op verschillende manieren.","Ze kunnen grond meenemen en ergens anders weer neerleggen.","Dat noemen we erosie en afzetting.","Bij bochten stroomt het water sneller aan de buitenkant.","Daar slijt de oever vaak af.","Aan de binnenkant is de stroming rustiger.","Daar ontstaat soms een zandbank.","In Nederland zie je dit bij grote rivieren zoals de Waal.","Rivieren veranderen het land doordat water steeds blijft bewegen.","Daarom ziet een riviergebied er na jaren anders uit."], highlightedIndex:2, correctLabel:"detail", uitleg:"De termen zijn uitlegdetail."},
  {id:28, onderwerp:"verhaal", zinnen:["Jayden had een plan om de klas te verrassen.","Hij wilde een complimentenpot maken zonder dat iemand het wist.","In de pauze schreef hij stiekem drie briefjes.","Op één briefje stond: 'Jij kunt supergoed uitleggen.'","Hij stopte de briefjes in een lege pot met een deksel.","Na school plakte hij er een label op: 'Pak er één als je een oppepper nodig hebt.'","De volgende ochtend zette hij de pot op de kast.","Iedereen was nieuwsgierig en wilde weten wie het had gedaan.","Een klein gebaar kan de sfeer in de klas echt beter maken.","Jayden glimlachte en zei niks."], highlightedIndex:3, correctLabel:"detail", uitleg:"De tekst op één briefje is een voorbeeld."},
  {id:29, onderwerp:"wetenschap", zinnen:["Lucht lijkt leeg, maar er zit van alles in.","Er zitten gassen in zoals stikstof en zuurstof.","Mensen ademen zuurstof in om energie te maken.","Planten gebruiken koolstofdioxide om te groeien.","Daarbij maken ze zuurstof.","Dat heet fotosynthese.","In een gesloten pot met een plant kan de lucht langzaam veranderen.","Je merkt het niet direct, maar het gebeurt wel.","Lucht is een mengsel dat belangrijk is voor mensen én planten.","Daarom noemen we lucht onzichtbaar, maar niet onbelangrijk."], highlightedIndex:5, correctLabel:"detail", uitleg:"‘Fotosynthese’ is een specifiek begrip."},
  {id:30, onderwerp:"rekenen", zinnen:["Als je een grote som maakt, helpt het om slim te schatten.","Je rondt getallen dan een beetje af.","Daarmee check je of je antwoord ongeveer klopt.","Bij 198 plus 403 kun je denken aan 200 plus 400.","Dan kom je op ongeveer 600.","Daarna reken je precies uit wat het echt is.","Schatten voorkomt dat je een veel te groot of klein antwoord opschrijft.","In de klas doen we dit vaak bij verhaalsommen.","Schatten helpt je om rekenfouten sneller te ontdekken.","Daarom is het een handige strategie."], highlightedIndex:3, correctLabel:"detail", uitleg:"Dit is één voorbeeldsom."},
  {id:31, onderwerp:"verkeer", zinnen:["Veilig fietsen begint met goed kijken.","Je kijkt vooruit, maar ook om je heen.","Voor je afslaat, geef je richting aan en kijk je achterom.","Dan weten anderen wat jij gaat doen.","Ook is het slim om je snelheid aan te passen bij drukte.","Bij een kruispunt kun je beter even wachten dan haasten.","Een bel kan helpen om iemand te waarschuwen.","In onze straat is er slecht zicht door geparkeerde auto’s.","Als je rustig en duidelijk fietst, gebeuren er minder ongelukken.","Daarom oefenen we verkeersregels op school."], highlightedIndex:7, correctLabel:"detail", uitleg:"Dit is één specifieke situatie."},
  {id:32, onderwerp:"kunst", zinnen:["Een schilderij kan een gevoel oproepen zonder woorden.","Sommige kunstenaars gebruiken felle kleuren voor energie.","Andere kiezen zachte kleuren voor rust.","Ook de manier van schilderen maakt verschil.","Met dikke verfstrepen ziet het er stoer uit.","Met dunne verf lijkt het juist netjes.","In de les maakten we een landschap met alleen drie kleuren.","Daarna vergeleken we hoe iedereen iets anders had gemaakt.","Kunst laat zien dat je op veel manieren hetzelfde onderwerp kunt tonen.","Daarom is kunst kijken en maken zo interessant."], highlightedIndex:6, correctLabel:"detail", uitleg:"De opdracht is een voorbeeld."},
  {id:33, onderwerp:"natuur", zinnen:["Bomen hebben in elk seizoen een andere taak.","In de lente maken ze nieuwe blaadjes.","In de zomer vangen die blaadjes veel zonlicht op.","In de herfst laten veel bomen hun bladeren los.","Dat bespaart energie als het kouder wordt.","In de winter rust de boom als het ware.","Sommige bomen blijven groen, zoals dennen.","Die hebben naalden die minder water verliezen.","Seizoenen zorgen ervoor dat bomen zich steeds aanpassen.","Daardoor kunnen ze het hele jaar overleven."], highlightedIndex:7, correctLabel:"detail", uitleg:"Dennen/naalden is een voorbeeld."},
  {id:34, onderwerp:"verhaal", zinnen:["Eline kreeg een kaartje in haar broodtrommel.","Er stond: 'Volg de pijlen na school.'","Ze dacht eerst dat het een grap was.","Toch zag ze op de stoep een krijtpijl richting het park.","Bij de schommel hing een lintje aan de ketting.","Verderop lagen nog twee pijlen, steeds dichter bij de vijver.","Daar stond haar beste vriendin met een kleine picknick.","Het was een verrassing om hun vriendschap te vieren.","Soms maakt iemand je dag beter met een eenvoudige verrassing.","Eline zei: 'Dit vergeet ik nooit meer.'"], highlightedIndex:3, correctLabel:"detail", uitleg:"De krijtpijl is een detail."},
  {id:35, onderwerp:"techniek", zinnen:["Een batterij bevat opgeslagen energie.","Die energie kan worden omgezet in elektriciteit.","Daarmee kunnen apparaten werken, zoals een zaklamp.","In een zaklamp loopt stroom door een lampje.","Dan gaat het lampje branden.","Als de batterij leeg is, werkt de zaklamp niet meer.","Sommige batterijen kun je opladen.","Dan gebruik je weer stroom om ze vol te maken.","Batterijen zijn handig omdat je stroom mee kunt nemen zonder stopcontact.","Daarom zitten ze in veel apparaten."], highlightedIndex:8, correctLabel:"hoofdzaak", uitleg:"Deze zin is de kernconclusie."},
  {id:36, onderwerp:"taal", zinnen:["Een alinea gaat vaak over één deelonderwerp.","De eerste zin van een alinea geeft soms al een hint.","Daarna volgen uitleg of voorbeelden.","Als je vastloopt, helpt het om jezelf vragen te stellen.","Waar gaat dit stuk over?","Welke zin vertelt het belangrijkste?","Soms kun je de hoofdzaak in je eigen woorden zeggen.","Dan weet je of je het begrijpt.","Met goede vragen vind je sneller de hoofdgedachte.","Daarom is actief lezen zo belangrijk."], highlightedIndex:1, correctLabel:"detail", uitleg:"Dit is één tip en dus detail."},
  {id:37, onderwerp:"dieren", zinnen:["Dolfijnen leven in groepen die je scholen noemt.","Ze communiceren met geluiden en bewegingen.","Sommige dolfijnen maken klikgeluiden om te 'zien' met echo’s.","Dat heet echolocatie.","Zo vinden ze vissen, zelfs in donker water.","Dolfijnen spelen ook vaak met elkaar.","Ze springen boven het water en draaien rond.","In een natuurfilm zag ik een dolfijn die zeewier als speelgoed gebruikte.","Dolfijnen zijn slim en gebruiken geluid om te jagen en te communiceren.","Daarom vinden mensen ze zo fascinerend."], highlightedIndex:3, correctLabel:"detail", uitleg:"‘Echolocatie’ is een detailbegrip."},
  {id:38, onderwerp:"verhaal", zinnen:["Op de eerste sneeuwdag rende Amir naar buiten.","Hij wilde als eerste voetstappen maken in de witte tuin.","Zijn handschoenen lagen nog binnen, maar dat maakte hem niks uit.","Hij rolde een klein sneeuwballetje en duwde het door het gras.","Elke ronde werd de bal groter en zwaarder.","Toen hij hem optilde, viel hij bijna om.","Zijn zus kwam erbij met een wortel en twee knopen.","Samen maakten ze een sneeuwpop met een scheve glimlach.","Samen iets maken is vaak leuker dan alles alleen doen.","Amir voelde zich warm, zelfs in de kou."], highlightedIndex:4, correctLabel:"detail", uitleg:"Dit is een specifieke gebeurtenis in het verhaal."},
  {id:39, onderwerp:"aardrijkskunde", zinnen:["Een klimaat vertelt iets over het weer over een lange tijd.","Het weer kan morgen heel anders zijn dan vandaag.","Het klimaat verandert niet per dag, maar over jaren.","In Nederland hebben we vaak zachte winters en koele zomers.","Dat komt onder andere door de zee en de wind.","In landen dichtbij de evenaar is het vaak warmer.","Daar is de zonkracht het hele jaar groter.","In de Sahara kan het overdag extreem warm zijn en ’s nachts koud.","Klimaat gaat over patronen in temperatuur en neerslag over lange tijd.","Daarom is het iets anders dan het weerbericht."], highlightedIndex:7, correctLabel:"detail", uitleg:"De Sahara is een voorbeeld."},
  {id:40, onderwerp:"gezondheid", zinnen:["Slaap is belangrijk voor je lichaam en je hoofd.","Tijdens slaap verwerkt je brein wat je hebt geleerd.","Ook groeien kinderen juist veel in hun slaap.","Als je te laat naar bed gaat, ben je vaker prikkelbaar.","Je kunt dan minder goed onthouden wat je leest.","Een vast ritme helpt om sneller in slaap te vallen.","Een scherm vlak voor slapen kan het lastiger maken.","Blauw licht houdt je brein langer wakker.","Genoeg slaap helpt je om beter te leren en je fijner te voelen.","Daarom is op tijd naar bed gaan slim."], highlightedIndex:7, correctLabel:"detail", uitleg:"Blauw licht is specifieke uitleg."},
  {id:41, onderwerp:"verhaal", zinnen:["Lotte oefende al dagen voor haar spreekbeurt.","Ze had kaartjes gemaakt met korte steekwoorden.","Toch begon haar stem te trillen toen ze voor de klas stond.","Ze keek even naar haar beste vriend die een duim opstak.","Toen haalde ze diep adem en begon ze rustig te praten.","Na de eerste minuut ging het ineens veel beter.","Ze vertelde over vulkanen en liet een plaatje zien van lava.","Aan het einde klapte de klas harder dan ze had verwacht.","Als je doorzet, merk je dat spanning vaak minder wordt.","Lotte voelde zich trots en opgelucht."], highlightedIndex:6, correctLabel:"detail", uitleg:"Het plaatje van lava is detail."},
  {id:42, onderwerp:"techniek", zinnen:["Een robot is een machine die taken kan uitvoeren.","Sommige robots bewegen met wielen en andere met armen.","Robots werken vaak met sensoren die meten wat er gebeurt.","Een sensor kan bijvoorbeeld licht of afstand meten.","Daarna beslist een computer wat de robot moet doen.","Robots worden gebruikt in fabrieken, maar ook in ziekenhuizen.","Een operatie-robot kan een arts heel precies helpen.","Toch beslist een arts altijd mee.","Robots zijn handig omdat ze taken kunnen herhalen zonder moe te worden.","Daarom zie je ze steeds vaker."], highlightedIndex:3, correctLabel:"detail", uitleg:"Dit is een voorbeeld van een sensor."},
  {id:43, onderwerp:"natuur", zinnen:["Water kan in drie vormen voorkomen: vast, vloeibaar en gas.","IJs is water in vaste vorm.","Vloeibaar water zie je in een glas of in een rivier.","Waterdamp is gas en zit in de lucht.","Als water warm wordt, verdampt het.","Als water koud wordt, bevriest het.","Bij afkoelen van waterdamp kan het condenseren tot druppels.","Daarom zie je soms een beslagen spiegel na het douchen.","Temperatuur zorgt dat water van vorm kan veranderen.","Dat gebeurt elke dag om ons heen."], highlightedIndex:7, correctLabel:"detail", uitleg:"De beslagen spiegel is een voorbeeld."},
  {id:44, onderwerp:"verhaal", zinnen:["Toen Sem zijn tas opende, zag hij dat zijn schrift nat was.","Een flesje drinken was opengegaan in het zijvak.","Hij baalde, want hij had net een nette bladzijde gemaakt.","In de gang kwam hij Nina tegen, die altijd tape bij zich had.","Ze gaf hem keukenpapier en een rolletje tape.","Samen maakten ze een ‘droogstation’ op de vensterbank.","Na tien minuten waren de blaadjes bijna droog.","Sem bedankte haar en zei dat hij haar ooit zou helpen.","Soms lost een klein probleem snel op met hulp van iemand anders.","Die dag liep toch nog goed af."], highlightedIndex:1, correctLabel:"detail", uitleg:"Het opengegaan flesje is detail."},
  {id:45, onderwerp:"rekenen", zinnen:["Percentages laten zien welk deel je bedoelt van honderd.","50 procent betekent de helft.","25 procent is een kwart.","Als iets 10 procent goedkoper is, haal je 10 van de 100 weg.","Bij 200 euro is 10 procent dus 20 euro.","Dan betaal je 180 euro.","Soms helpt het om eerst 1 procent uit te rekenen.","Dan kun je snel meerdere procenten maken.","Percentages helpen om kort en duidelijk over delen te praten.","Daarom kom je ze vaak tegen in winkels en nieuws."], highlightedIndex:4, correctLabel:"detail", uitleg:"Dit is een rekenvoorbeeld."},
  {id:46, onderwerp:"verhaal", zinnen:["Noa wilde een nieuw trucje leren op haar skateboard.","Ze keek een filmpje en schreef drie stappen op.","Eerst moest ze haar voeten precies goed zetten.","Daarna oefende ze het springen zonder te rijden.","Toen probeerde ze het langzaam vooruit.","De eerste vijf keer ging het mis en landde ze scheef.","Ze werd boos, maar haar broer zei: 'Nog één keer rustig.'","Bij de zevende poging lukte het ineens.","Door te blijven oefenen leer je nieuwe dingen, ook als het eerst niet lukt.","Noa reed weg met een grote glimlach."], highlightedIndex:5, correctLabel:"detail", uitleg:"‘De eerste vijf keer’ is detail met getal."},
  {id:47, onderwerp:"aardrijkskunde", zinnen:["Kaarten zijn een verkleinde weergave van de werkelijkheid.","Je gebruikt symbolen om dingen aan te geven, zoals wegen en water.","Een legenda vertelt wat de symbolen betekenen.","Met een schaal kun je afstanden omrekenen.","Als de schaal 1 op 10.000 is, is 1 cm op de kaart 100 meter in het echt.","Noord staat vaak bovenaan, maar dat hoeft niet altijd.","Met coördinaten kun je een plek precies aanwijzen.","In de atlas vind je een stad met het register.","Kaarten helpen je om plaatsen en afstanden beter te begrijpen.","Daarom gebruiken we ze bij aardrijkskunde."], highlightedIndex:4, correctLabel:"detail", uitleg:"De schaal-uitleg is specifieke detailinfo."},
  {id:48, onderwerp:"sport", zinnen:["Bij zwemmen is techniek belangrijker dan brute kracht.","Als je goed stroomlijnt, ga je sneller door het water.","Je houdt je hoofd rustig en kijkt naar beneden.","Je armen maken lange halen, niet korte snelle tikjes.","Ook je benen helpen, maar ze moeten niet alle energie opmaken.","Daarom oefen je vaak met een plankje.","In de les deden we drie banen alleen met benen.","Daarna merkte ik pas hoe zwaar dat is.","Goede techniek zorgt dat je langer kunt zwemmen zonder moe te worden.","Dat maakt zwemmen leuker en veiliger."], highlightedIndex:6, correctLabel:"detail", uitleg:"Drie banen is een concreet voorbeeld."},
  {id:49, onderwerp:"natuur", zinnen:["Vogels hebben verschillende snavels voor verschillend voedsel.","Een eend heeft een platte snavel om uit water te filteren.","Een specht heeft een stevige snavel om in bomen te tikken.","Een roofvogel heeft een kromme snavel om vlees te scheuren.","Zo past een snavel bij de leefwijze van een vogel.","Daarom kun je aan een snavel vaak raden wat een vogel eet.","Soms zie je een vink met een korte sterke snavel bij zaden.","In de winter zoeken veel vogels extra voedsel omdat er minder insecten zijn.","De vorm van een snavel laat zien hoe dieren zich aanpassen aan hun omgeving.","Dat maakt vogels leuk om te bestuderen."], highlightedIndex:6, correctLabel:"detail", uitleg:"De vink is een voorbeeld."},
  {id:50, onderwerp:"verhaal", zinnen:["Tijdens de pauze hoorde de klas ineens een rare piep.","Iedereen keek naar de kast waar de chromebooks lagen.","Daar kwam het geluid vandaan, alsof er een muis zat.","De meester opende voorzichtig de deur en stapte achteruit.","In plaats van een muis rolde er een piepklein speelgoedautootje uit.","Iemand had het autootje per ongeluk aangezet en het zat vast.","De klas moest heel hard lachen.","Toen zette de meester het autootje op het bureau en liet het rondrijden.","Een kleine verrassing kan de dag op school extra gezellig maken.","Daarna ging iedereen weer rustig aan het werk."], highlightedIndex:4, correctLabel:"detail", uitleg:"Het autootje is een specifieke gebeurtenis."},
  {id:51, onderwerp:"vulkanen", zinnen:["Een vulkaan laat goed zien hoeveel kracht er diep in de aarde verborgen zit.","Diep onder de grond is gesteente zo heet dat het vloeibaar wordt.","Dat gloeiende gesteente noemen we magma.","Soms zoekt het magma langzaam een weg naar boven.","Komt het aan de oppervlakte, dan spreken we van lava.","Bij een uitbarsting spuwt de vulkaan ook as en gas de lucht in.","De as kan soms kilometers ver wegwaaien.","Toch wordt de grond rond een vulkaan na verloop van tijd erg vruchtbaar.","Daarom durven mensen er toch dichtbij te wonen.","Onderzoekers meten vulkanen om op tijd te kunnen waarschuwen."], highlightedIndex:0, correctLabel:"hoofdzaak", uitleg:"Deze openingszin vertelt waar het hele stukje over gaat."},
  {id:52, onderwerp:"oceaan", zinnen:["Aan de kust lijkt de zee al enorm, maar dat is nog maar het begin.","Verder weg wordt het water steeds dieper.","Op sommige plekken is de bodem meer dan tien kilometer naar beneden.","Daar is het pikdonker en ijskoud.","Toch leven er bijzondere dieren die zelf licht maken.","Sommige vissen hebben een lampje aan hun kop.","Onderzoekers gebruiken speciale duikboten om er te kijken.","Veel van de diepzee is nog nooit door mensen gezien.","We weten er minder van dan van de maan.","De oceaan is een van de grootste raadsels van onze eigen planeet."], highlightedIndex:9, correctLabel:"hoofdzaak", uitleg:"De slotzin vat de grote boodschap van de tekst samen."},
  {id:53, onderwerp:"vlinders", zinnen:["Een vlinder begint zijn leven niet als vlinder, maar als rups.","De rups eet veel blaadjes en groeit snel.","Daarna maakt hij een pop om zich heen.","In de pop verandert zijn lichaam helemaal.","Sommige vlinders zitten wel twee weken in hun pop.","Uiteindelijk kruipt er een vlinder uit.","Eerst zijn de vleugels nog klein en slap.","Na een uurtje drogen kan de vlinder pas vliegen.","Zo verandert een kruipend dier in een fladderend dier.","Die hele verandering heet metamorfose."], highlightedIndex:4, correctLabel:"detail", uitleg:"Dit is specifieke informatie over hoe lang, niet de kern."},
  {id:54, onderwerp:"romeinen", zinnen:["Lang geleden hadden de Romeinen een groot rijk.","De Romeinen waren vooral knap in het bouwen van handige dingen.","Ze legden rechte wegen aan die honderden kilometers ver liepen.","Over die wegen konden soldaten en handelaren snel reizen.","Ook bouwden ze waterleidingen van steen, aquaducten genoemd.","Daarmee brachten ze schoon water tot in de stad.","In hun badhuizen konden mensen zich wassen en elkaar ontmoeten.","Sommige Romeinse bruggen staan na tweeduizend jaar nog overeind.","Veel van hun ideeën gebruiken we vandaag nog steeds.","Daarom leren we op school over deze slimme bouwers."], highlightedIndex:1, correctLabel:"hoofdzaak", uitleg:"Dit is de kerngedachte; de rest geeft er voorbeelden bij."},
  {id:55, onderwerp:"recyclen", zinnen:["Door afval te scheiden help je mee om grondstoffen te besparen.","Oud papier kun je opnieuw tot nieuw papier maken.","Glas gaat in de glasbak en wordt omgesmolten.","Van plastic flessen kunnen zelfs truien worden gemaakt.","Daarvoor moet je het afval wel goed in de juiste bak doen.","Een pizzadoos met vet hoort niet bij het schone papier.","In veel gemeenten haalt de vuilniswagen alles apart op.","Thuis kun je met aparte bakjes al beginnen.","Het kost even moeite, maar het scheelt veel nieuwe grondstoffen.","Zo gooi je veel minder zomaar weg."], highlightedIndex:0, correctLabel:"hoofdzaak", uitleg:"Deze openingszin geeft het hoofddoel van de hele tekst."},
  {id:56, onderwerp:"schaken", zinnen:["Schaken is een spel waarbij je steeds vooruit moet denken.","Elk stuk mag op een eigen manier bewegen.","Het paard maakt bijvoorbeeld een sprong in de vorm van een L.","De toren gaat in rechte lijnen vooruit en opzij.","Je probeert de koning van de ander klem te zetten.","Daarvoor maak je vaak een plan van een paar zetten.","Soms moet je een stuk opofferen om later te winnen.","Geduld is bij schaken net zo belangrijk als snelheid.","Door veel te spelen ga je steeds slimmere zetten zien.","Schaken traint je om rustig en vooruit te denken."], highlightedIndex:2, correctLabel:"detail", uitleg:"Dit is één voorbeeld van een regel, niet de kern."},
  {id:57, onderwerp:"woestijn", zinnen:["In een woestijn valt heel weinig regen.","Overdag kan het er gloeiend heet worden.","Maar 's nachts koelt het juist snel af.","Planten en dieren moeten er zuinig zijn met water.","Een cactus slaat water op in zijn dikke stam.","Een kameel kan dagen zonder drinken.","Sommige dieren komen alleen 's nachts tevoorschijn.","Dan is het koeler en verliezen ze minder vocht.","Alles in de woestijn is aangepast aan een leven met weinig water.","Daardoor is het er toch niet zo leeg als het lijkt."], highlightedIndex:8, correctLabel:"hoofdzaak", uitleg:"Deze zin vat de hele tekst samen: aanpassen aan weinig water."},
  {id:58, onderwerp:"lichaam", zinnen:["Je hart is een spier die je hele leven blijft doorwerken.","Het pompt bloed door je hele lichaam.","Met dat bloed komt zuurstof bij al je spieren.","Als je rent, gaat je hart sneller kloppen.","Je spieren hebben dan namelijk meer zuurstof nodig.","Je kunt je hartslag voelen in je pols.","Door te sporten wordt je hart sterker.","Een sterk hart hoeft in rust minder hard te werken.","Gezond eten helpt je hart ook.","Daarom is bewegen zo goed voor je lijf."], highlightedIndex:0, correctLabel:"hoofdzaak", uitleg:"Deze openingszin geeft de hoofdgedachte over het hart."},
  {id:59, onderwerp:"verhaal", zinnen:["Tijn en Bo zaten niet bij elkaar in de klas.","Toch werden ze tijdens een schoolreisje vrienden.","Ze moesten samen een opdracht doen in het bos.","Tijn wist veel over planten en Bo durfde overal op te klimmen.","Samen vonden ze sneller alle antwoorden.","Onderweg moesten ze om dezelfde grappen lachen.","Na het reisje speelden ze ook in het weekend samen.","Soms hadden ze ruzie, maar dat losten ze weer op.","Ze merkten dat ze elkaar goed aanvulden.","Echte vriendschap kan op de gekste momenten ontstaan."], highlightedIndex:9, correctLabel:"hoofdzaak", uitleg:"De slotzin geeft de boodschap van het hele verhaal."},
  {id:60, onderwerp:"geld", zinnen:["Sparen helpt je om later iets groters te kunnen kopen.","Als je elke week een beetje opzij legt, groeit je spaarpot.","Stel, je wilt een step van veertig euro.","Met twee euro per week duurt dat twintig weken.","Dat lijkt lang, maar het went snel.","Je kunt je doel op een briefje schrijven.","Dan zie je steeds waarvoor je spaart.","Soms is het lastig om niet meteen iets kleins te kopen.","Toch is het fijn als je doel eindelijk dichtbij komt.","Geduld wordt bij sparen vaak beloond."], highlightedIndex:0, correctLabel:"hoofdzaak", uitleg:"Deze openingszin vertelt waar het hele stukje over gaat."},
  {id:61, onderwerp:"natuur", zinnen:["In een tropisch regenwoud regent het bijna elke dag.","Daardoor groeien er ontzettend veel planten.","De bomen worden er hoog en staan dicht op elkaar.","Bovenin vormen de bladeren een groen dak.","Onder dat dak is het schemerig en vochtig.","Er leven meer dieren dan op bijna elke andere plek.","Kleurige vogels, apen en insecten wonen in de bomen.","Veel van die dieren vind je nergens anders.","Wetenschappers ontdekken er nog steeds nieuwe soorten.","Het regenwoud is een van de rijkste plekken aan leven op aarde."], highlightedIndex:9, correctLabel:"hoofdzaak", uitleg:"De slotzin vat de hoofdgedachte van de tekst samen."},
  {id:62, onderwerp:"natuur", zinnen:["Paddenstoelen zie je vooral in de herfst tevoorschijn komen.","Ze houden van vochtige en koele plekken.","Onder de grond zit een netwerk van dunne draden.","De paddenstoel die je ziet, is eigenlijk maar een klein deel.","Sommige paddenstoelen zijn felrood met witte stippen.","Die mooie kleur betekent vaak: niet opeten.","Veel soorten zijn namelijk giftig.","Daarom pluk je ze nooit zomaar om te proeven.","Paddenstoelen helpen de natuur door dood hout op te ruimen.","Zo maken ze plaats voor nieuwe groei."], highlightedIndex:4, correctLabel:"detail", uitleg:"Dit beschrijft één soort; het is een voorbeeld."},
  {id:63, onderwerp:"uitvindingen", zinnen:["Vroeger moest je een brief dagenlang laten bezorgen.","Veel uitvindingen zijn bedacht om het leven makkelijker te maken.","De telefoon zorgde dat je ineens ver weg kon praten.","De wasmachine nam zwaar werk uit handen.","Met de fiets kon je sneller dan lopen reizen.","Later kwamen auto's, treinen en vliegtuigen.","Niet elke uitvinding werkte meteen goed.","Vaak werd een idee stap voor stap verbeterd.","De ene bedenker bouwde voort op het werk van een ander.","Zo veranderde de wereld langzaam maar zeker."], highlightedIndex:1, correctLabel:"hoofdzaak", uitleg:"Dit is de kerngedachte; de rest geeft er voorbeelden bij."},
  {id:64, onderwerp:"koken", zinnen:["Zelf leren koken doe je het best door het gewoon te doen.","Je begint met een makkelijk gerecht, zoals pasta.","Eerst lees je het hele recept rustig door.","Dan leg je alle spullen vast klaar.","Tijdens het koken let je goed op de tijd.","Te lang koken maakt groente slap en flauw.","Tussendoor proeven helpt je om te weten of het klopt.","Een beetje zout kan al veel verschil maken.","Maak je een foutje, dan leer je daar juist van.","Met oefenen wordt koken steeds leuker."], highlightedIndex:0, correctLabel:"hoofdzaak", uitleg:"Deze openingszin geeft de hoofdgedachte van de tekst."},
  {id:65, onderwerp:"dans", zinnen:["Dansen is bewegen op het ritme van muziek.","Je kunt het alleen doen of met een groep.","Bij een groepsdans moet iedereen op hetzelfde moment bewegen.","Daarom tellen dansers vaak mee: vijf, zes, zeven, acht.","Door te oefenen onthoud je de passen steeds beter.","Eerst gaat het langzaam, daarna op snelheid.","Sommige dansen vertellen zelfs een heel verhaal.","Je gezicht en handen doen dan mee met het gevoel.","Dansen zorgt dat je je vrij en vrolijk voelt.","Daarom dansen mensen over de hele wereld."], highlightedIndex:3, correctLabel:"detail", uitleg:"Dit is een concreet voorbeeld, geen kern."},
  {id:66, onderwerp:"geschiedenis", zinnen:["De Vikingen kwamen lang geleden uit het hoge noorden.","Ze waren bekend als stoere zeevaarders.","Met lange smalle boten staken ze grote zeeën over.","Soms gingen ze op rooftocht naar verre kusten.","Maar ze waren ook handelaren die spullen ruilden.","Ze brachten bont, ijzer en sieraden mee.","Thuis vertelden ze sterke verhalen bij het vuur.","Over hun goden bestaan nog steeds veel mythes.","Niet alles wat we over hen horen is even waar.","De Vikingen waren dus veel meer dan alleen vechters."], highlightedIndex:9, correctLabel:"hoofdzaak", uitleg:"De slotzin vat de hoofdboodschap van de tekst samen."},
  {id:67, onderwerp:"ruimte", zinnen:["Een ster lijkt klein, maar is eigenlijk een gigantische bal van gas.","Sterren staan zo ver weg dat ze als stipjes lijken.","Onze zon is ook een ster, maar dan dichtbij.","Daarom lijkt de zon zoveel groter dan andere sterren.","Het licht van verre sterren doet er jaren over om hier te komen.","Sommige sterren zie je dus zoals ze lang geleden waren.","In een heldere nacht buiten de stad zie je er duizenden.","Vroeger gebruikten zeelui de sterren om de weg te vinden.","Ze keken naar vaste patronen aan de hemel.","Zo wezen de sterren hun de richting."], highlightedIndex:0, correctLabel:"hoofdzaak", uitleg:"Deze openingszin geeft de kerngedachte over sterren."},
  {id:68, onderwerp:"emoties", zinnen:["Soms voel je je boos zonder dat je precies weet waarom.","Misschien heb je honger of ben je moe.","Emoties geven je lichaam een seintje.","Blij zijn voelt licht en energiek.","Bang zijn maakt je hart sneller.","Het helpt om je gevoel een naam te geven.","Als je zegt 'ik ben verdrietig', snapt een ander je beter.","Praten lucht vaak meer op dan je denkt.","Ook diep ademhalen kan je rustiger maken.","Je gevoelens begrijpen helpt je om er beter mee om te gaan."], highlightedIndex:9, correctLabel:"hoofdzaak", uitleg:"De slotzin geeft de hoofdgedachte van de tekst."},
  {id:69, onderwerp:"fotografie", zinnen:["Iedereen maakt tegenwoordig foto's met een telefoon.","Een goede foto maken is meer dan zomaar op de knop drukken.","Je let op het licht dat op je onderwerp valt.","Met de zon achter je wordt een foto vaak helderder.","Ook kies je wat je wel en niet in beeld wilt.","Soms is minder in beeld juist mooier.","Even stilstaan voorkomt een wazige foto.","Van dichtbij zie je kleine details die anders verdwijnen.","Door veel te proberen ontdek je wat werkt.","Zo wordt een gewoon kiekje ineens een mooie foto."], highlightedIndex:1, correctLabel:"hoofdzaak", uitleg:"Dit is de kerngedachte; de rest legt uit hoe."},
  {id:70, onderwerp:"middeleeuwen", zinnen:["In de middeleeuwen bouwden mensen sterke kastelen.","Een kasteel moest de bewoners beschermen tegen vijanden.","Daarom waren de muren vaak metersdik.","Rondom lag soms een gracht vol water.","Over de gracht lag een ophaalbrug die omhoog kon.","Was er gevaar, dan trok men de brug snel op.","Boven op de muren stonden wachters op de uitkijk.","Vanuit smalle gaten konden ze naar buiten kijken.","Een kasteel was zo een veilige plek in onrustige tijden.","Veel kastelen kun je nu nog steeds bezoeken."], highlightedIndex:4, correctLabel:"detail", uitleg:"Dit is een concreet onderdeel, niet de kern."},
  {id:71, onderwerp:"dieren", zinnen:["In de herfst zie je soms grote groepen vogels wegvliegen.","Ze gaan naar warmere landen in het zuiden.","Daar is genoeg eten als het hier koud wordt.","Sommige vogels vliegen wel duizenden kilometers.","Onderweg rusten ze uit op vaste plekken.","Ze vliegen vaak in een V-vorm.","Zo hoeft niet elke vogel even hard te werken.","In de lente komen ze weer terug om te broeden.","Trekvogels reizen mee met het wisselen van de seizoenen.","Daarom zie je ze niet het hele jaar."], highlightedIndex:8, correctLabel:"hoofdzaak", uitleg:"Deze zin vat het hele stukje samen."},
  {id:72, onderwerp:"gezondheid", zinnen:["Goed je tanden poetsen voorkomt gaatjes en pijn.","In je mond zitten heel kleine bacteriën.","Die houden van suiker uit snoep en frisdrank.","Ze maken er een zuur van dat je tanden aantast.","Twee keer per dag poetsen ruimt veel bacteriën op.","'s Avonds poetsen is extra belangrijk.","In je slaap maak je namelijk minder speeksel aan.","Een tandarts controleert af en toe je gebit.","Zo ontdek je een probleempje op tijd.","Met goede gewoonten blijven je tanden langer gezond."], highlightedIndex:0, correctLabel:"hoofdzaak", uitleg:"Deze openingszin geeft de hoofdgedachte."},
  {id:73, onderwerp:"weer", zinnen:["Wind voel je wel, maar je ziet hem nooit.","Wind ontstaat doordat lucht van plek wisselt.","Warme lucht stijgt op en koele lucht stroomt erheen.","Die beweging van lucht noemen we wind.","Bij weinig verschil waait het zacht.","Bij een groot verschil kan het hard stormen.","Wind kan een zeilboot vooruit duwen.","Een windmolen draait er stroom mee op.","Maar een storm kan ook takken afbreken.","Wind is dus onzichtbaar, maar wel vol kracht."], highlightedIndex:9, correctLabel:"hoofdzaak", uitleg:"De slotzin vat de hoofdgedachte samen."},
  {id:74, onderwerp:"dieren", zinnen:["Spinnen zijn nuttige dieren, ook al schrikken veel mensen van ze.","Een spin maakt een web van dunne, kleverige draden.","In dat web blijven muggen en vliegen plakken.","Zo vangt de spin elke dag veel insecten.","Daardoor zijn er minder vervelende muggen in huis.","Het web is sterker dan het lijkt.","De spin voelt aan trillingen dat er prooi vastzit.","Sommige spinnen maken elke nacht een nieuw web.","Een spin is dus geen gevaar, maar een helper.","Daarom laat je een spin beter rustig zitten."], highlightedIndex:0, correctLabel:"hoofdzaak", uitleg:"Deze openingszin geeft de kerngedachte over spinnen."},
  {id:75, onderwerp:"theater", zinnen:["In een theater spelen acteurs een verhaal na.","Ze leren van tevoren hun tekst uit hun hoofd.","Met hun stem en lichaam laten ze gevoelens zien.","Het decor maakt duidelijk waar het verhaal speelt.","Soms staat er een hele kamer op het toneel gebouwd.","Lampen zorgen voor de juiste sfeer.","Een spannend stuk krijgt vaak donker, blauw licht.","Achter de schermen helpen veel mensen mee.","Samen maken ze van het verhaal iets levends.","Daarom is naar het theater gaan iets bijzonders."], highlightedIndex:6, correctLabel:"detail", uitleg:"Dit is een concreet voorbeeld, geen kern."},
  {id:76, onderwerp:"rekenen", zinnen:["Met handig rekenen kun je sommen veel sneller oplossen.","Soms hoef je niet alles precies uit te rekenen.","Bij optellen mag je de getallen omdraaien.","Zeven plus drie is net zoveel als drie plus zeven.","Je kunt ook eerst tot een rond getal rekenen.","Van negenentwintig maak je makkelijk dertig.","Daarna haal je de ene die je te veel telde er weer af.","Zulke trucjes schelen veel tijd.","Ze helpen ook om minder fouten te maken.","Door te oefenen ga je ze vanzelf gebruiken."], highlightedIndex:0, correctLabel:"hoofdzaak", uitleg:"Deze openingszin geeft de hoofdgedachte."},
  {id:77, onderwerp:"natuur", zinnen:["Aan zee staat het water niet altijd even hoog.","Twee keer per dag komt het water op.","Dat noemen we vloed.","Daarna trekt het zich weer terug, en dat heet eb.","Bij eb kun je over het droge strand lopen.","Schelpen en krabbetjes blijven dan achter.","De maan trekt aan het water van de zee.","Door die kracht ontstaat het komen en gaan.","Wie aan zee woont, houdt de tijden goed in de gaten.","Eb en vloed laten zien dat de maan invloed heeft op de aarde."], highlightedIndex:9, correctLabel:"hoofdzaak", uitleg:"De slotzin vat de hoofdgedachte samen."},
  {id:78, onderwerp:"taal", zinnen:["Sommige kinderen vinden lezen eerst niet zo leuk.","Toch kan een goed boek je helemaal meenemen naar een andere wereld.","Je leest over verre landen of spannende avonturen.","In je hoofd zie je de personen zo voor je.","Je leeft mee met wat hun overkomt.","Een boek kan je laten lachen of juist ontroeren.","Hoe meer je leest, hoe makkelijker het gaat.","Je leert ook steeds nieuwe woorden.","Het beste boek is er een dat bij jou past.","Daarom is er voor iedereen wel een mooi verhaal."], highlightedIndex:1, correctLabel:"hoofdzaak", uitleg:"Dit is de kerngedachte; de rest legt uit waarom."},
  {id:79, onderwerp:"dieren", zinnen:["Olifanten zijn de grootste landdieren op aarde.","Met hun slurf kunnen ze ontzettend veel.","Ze plukken er blaadjes mee en drinken er water mee.","Ook aaien ze elkaar met hun slurf.","Olifanten leven in een kudde bij elkaar.","De oudste vrouw wijst vaak de weg naar water.","Ze onthoudt plekken die ze jaren geleden zag.","Jonge olifantjes worden door de hele kudde beschermd.","Als er gevaar is, gaan de grote eromheen staan.","Olifanten zorgen samen heel goed voor elkaar."], highlightedIndex:9, correctLabel:"hoofdzaak", uitleg:"De slotzin vat de hoofdgedachte samen."},
  {id:80, onderwerp:"wetenschap", zinnen:["Alles wat je loslaat, valt naar beneden door de zwaartekracht.","De aarde trekt namelijk aan elk voorwerp.","Daarom valt een appel naar de grond en niet omhoog.","Ook jij wordt naar de aarde toe getrokken.","Daardoor blijf je gewoon op de grond staan.","Een zwaar voorwerp valt niet sneller dan een licht voorwerp.","Dat lijkt gek, maar het klopt echt.","Een veertje valt alleen langzamer door de lucht.","In de ruimte voel je bijna geen zwaartekracht.","Daar zweven astronauten rond in hun ruimteschip."], highlightedIndex:0, correctLabel:"hoofdzaak", uitleg:"Deze openingszin geeft de kerngedachte."},
  {id:81, onderwerp:"natuur", zinnen:["In de zee drijft op sommige plekken heel veel plastic.","Dat plastic komt vaak van het land.","Een weggegooid flesje kan via een rivier in zee belanden.","Door de zon en de golven valt het in kleine stukjes uiteen.","Vissen denken soms dat het eten is.","Zo komt plastic in de buik van dieren terecht.","Vrijwilligers ruimen stranden op om te helpen.","Maar opruimen alleen is niet genoeg.","Het is beter om minder plastic weg te gooien.","Goed omgaan met afval houdt de zee schoner."], highlightedIndex:9, correctLabel:"hoofdzaak", uitleg:"De slotzin vat de hoofdgedachte samen."},
  {id:82, onderwerp:"aardrijkskunde", zinnen:["Nederland is een land dat altijd vecht tegen het water.","Een groot deel ligt lager dan de zee.","Zonder bescherming zou het hier vaak overstromen.","Daarom bouwden mensen dijken langs het water.","Een dijk is een hoge wal van grond.","Vroeger pompten windmolens het water weg.","Nu doen sterke gemalen dat werk.","Bij storm sluiten grote keringen de zee af.","Zo blijven de voeten van het land droog.","Water hoort echt bij de geschiedenis van Nederland."], highlightedIndex:0, correctLabel:"hoofdzaak", uitleg:"Deze openingszin geeft de hoofdgedachte van de tekst."},
  {id:83, onderwerp:"muziek", zinnen:["Een gitaar maakt geluid met snaren.","Als je aan een snaar plukt, gaat hij trillen.","Die trilling hoor je als een toon.","Een dikke snaar geeft een lage toon.","Een dunne snaar klinkt juist hoog.","Met je vingers kun je een snaar korter maken.","Dan verandert de toon die je hoort.","De holle kast maakt het geluid harder.","Zo kun je met zes snaren heel veel tonen spelen.","Daarom is de gitaar zo'n veelzijdig instrument."], highlightedIndex:3, correctLabel:"detail", uitleg:"Dit is een specifiek voorbeeld, geen kern."},
  {id:84, onderwerp:"gezondheid", zinnen:["Iedereen droomt, ook al weet je het vaak niet meer.","Dromen gebeuren vooral in een diepe slaapfase.","Je hersenen verwerken dan wat je hebt meegemaakt.","Soms zijn dromen gek en onlogisch.","Je kunt ineens vliegen of praten met een dier.","Een nare droom heet een nachtmerrie.","Meestal ben je een droom binnen een minuut weer vergeten.","Opschrijven helpt om hem langer te onthouden.","Dromen horen gewoon bij een goede nachtrust.","Daarom is slapen meer dan alleen maar uitrusten."], highlightedIndex:5, correctLabel:"detail", uitleg:"Dit is een los begrip, niet de kern."},
  {id:85, onderwerp:"dieren", zinnen:["Pinguïns zijn vogels, maar ze kunnen niet vliegen.","In plaats daarvan zijn ze geweldige zwemmers.","Met hun vleugels peddelen ze snel door het water.","Hun gladde lijf glijdt makkelijk vooruit.","Op het land waggelen ze juist langzaam.","In de kou kruipen ze dicht tegen elkaar aan.","Zo houden ze samen de warmte vast.","De buitenste pinguïns wisselen steeds met de binnenste.","Niemand staat dus te lang in de kou.","Pinguïns overleven door slim samen te werken."], highlightedIndex:9, correctLabel:"hoofdzaak", uitleg:"De slotzin vat de hoofdgedachte samen."},
  {id:86, onderwerp:"techniek", zinnen:["In huis gebruik je de hele dag elektriciteit.","Elektriciteit is energie die door draden stroomt.","Met een schakelaar zet je die stroom aan of uit.","Een lamp gaat branden als de stroom erdoor loopt.","Ook de koelkast en de tv werken erop.","De stroom komt via kabels je huis binnen.","Buiten lopen die kabels onder de grond of in de lucht.","Bij water kan stroom gevaarlijk zijn.","Daarom raak je stopcontacten nooit met natte handen aan.","Met stroom omgaan vraagt dus om voorzichtigheid."], highlightedIndex:1, correctLabel:"hoofdzaak", uitleg:"Dit is de kerngedachte; de rest geeft er voorbeelden bij."},
  {id:87, onderwerp:"verhaal", zinnen:["Op maandag regende het hard toen de school uitging.","Roos had haar jas thuis laten liggen.","Ze stond te rillen onder het afdak bij de deur.","Toen kwam Daan aanlopen met een grote paraplu.","Hij bood aan om haar naar huis te brengen.","Samen liepen ze onder de paraplu door de plassen.","Onderweg vertelden ze elkaar moppen.","Bij Roos thuis was ze nog bijna droog.","Een klein gebaar kan iemands dag echt redden.","Roos zwaaide Daan dankbaar na."], highlightedIndex:3, correctLabel:"detail", uitleg:"Dit is een gebeurtenis in het verhaal, geen kern."},
  {id:88, onderwerp:"aardrijkskunde", zinnen:["Een gletsjer is een enorme rivier van ijs die heel langzaam beweegt.","Hoog in de bergen valt veel sneeuw.","Die sneeuw wordt door zijn gewicht samengeperst tot ijs.","Heel langzaam schuift het ijs naar beneden.","Per jaar gaat dat soms maar een paar meter.","Onderweg schuurt het ijs langs de rotsen.","Daardoor slijpt een gletsjer een heel dal uit.","Aan het eind smelt het ijs weer tot water.","Dat water vult beken en rivieren.","Veel drinkwater begint dus hoog op een berg."], highlightedIndex:0, correctLabel:"hoofdzaak", uitleg:"Deze openingszin geeft de kerngedachte over gletsjers."},
  {id:89, onderwerp:"spelling", zinnen:["Bij spelling moet je soms goed nadenken.","Sommige woorden klinken hetzelfde, maar schrijf je anders.","Denk aan 'hij wordt' en 'het woord'.","Bij werkwoorden helpt het om de regels te kennen.","Je kunt een woord langer maken om de laatste letter te horen.","Bij 'hond' hoor je in 'honden' de d.","Veel fouten ontstaan door te snel te schrijven.","Even teruglezen helpt om ze te vinden.","Hoe vaker je oefent, hoe automatischer het gaat.","Goede spelling leer je vooral door rustig te blijven oefenen."], highlightedIndex:9, correctLabel:"hoofdzaak", uitleg:"De slotzin vat de hoofdgedachte samen."},
  {id:90, onderwerp:"dieren", zinnen:["Een kameleon is een meester in zich verstoppen.","Dit dier kan van kleur veranderen.","Zo lijkt het op de tak of het blad waarop het zit.","Daardoor zien vijanden hem bijna niet.","Ook zijn ogen zijn bijzonder.","Ze kunnen elk een andere kant op kijken.","Zo houdt hij alles tegelijk in de gaten.","Zijn lange tong schiet razendsnel naar een insect.","In een tel heeft hij zijn prooi te pakken.","Met al die trucs overleeft de kameleon goed."], highlightedIndex:0, correctLabel:"hoofdzaak", uitleg:"Deze openingszin geeft de kerngedachte over de kameleon."},
  {id:91, onderwerp:"eten", zinnen:["Brood maken begint met meel, water en gist.","De gist zorgt dat het deeg gaat rijzen.","In het deeg ontstaan kleine luchtbelletjes.","Daardoor wordt het brood luchtig en zacht.","De bakker laat het deeg eerst een uur rusten.","Dan kneedt hij het nog een keer goed door.","In de hete oven wordt de korst bruin en knapperig.","De geur van vers brood ruik je door de hele winkel.","Zo wordt van een paar spullen een heel brood gemaakt.","Daarom is bakken een beetje toveren met deeg."], highlightedIndex:4, correctLabel:"detail", uitleg:"Dit is een concrete stap met een tijd, geen kern."},
  {id:92, onderwerp:"wetenschap", zinnen:["Een magneet kan ijzer naar zich toe trekken.","Een magneet heeft altijd twee kanten met een eigen kracht.","Die kanten noemen we de noordpool en de zuidpool.","Twee verschillende polen trekken elkaar aan.","Twee gelijke polen duwen elkaar juist weg.","Dat voel je goed met twee magneten in je hand.","Een kompas werkt ook met een kleine magneet.","Die naald wijst altijd naar het noorden.","Zo kun je met een magneet de weg vinden.","Magneten zijn dus handiger dan je zou denken."], highlightedIndex:1, correctLabel:"hoofdzaak", uitleg:"Dit is de kerngedachte; de rest legt het uit."},
  {id:93, onderwerp:"verhaal", zinnen:["Het had die nacht flink gesneeuwd.","Fenna kon haast niet wachten om naar buiten te gaan.","Met haar slee rende ze naar het kleine heuveltje in het park.","Boven gekomen ging ze zitten en duwde zich af.","Suizend gleed ze naar beneden, met sneeuw in haar gezicht.","Onderaan rolde ze lachend van de slee.","Steeds meer kinderen kwamen er ook met sleeën.","Samen maakten ze een gladde glijbaan in de sneeuw.","Een sneeuwdag maakt van een gewone heuvel een feest.","Pas toen het donker werd, ging Fenna naar binnen."], highlightedIndex:2, correctLabel:"detail", uitleg:"Dit is een concreet onderdeel van het verhaal."},
  {id:94, onderwerp:"ruimte", zinnen:["Om de zon draaien acht planeten in vaste banen.","De aarde is daar één van.","Sommige planeten zijn klein en van steen.","Andere zijn reuzen van gas, zoals Jupiter.","Hoe verder van de zon, hoe kouder het wordt.","Mercurius staat dichtbij en is gloeiend heet.","Op de aarde is het precies goed voor leven.","Er is water en het is niet te warm of te koud.","Dat maakt onze planeet bijzonder.","In ons zonnestelsel hoort elke planeet op zijn eigen plek thuis."], highlightedIndex:9, correctLabel:"hoofdzaak", uitleg:"De slotzin vat de hoofdgedachte samen."},
  {id:95, onderwerp:"sport", zinnen:["Sven wilde leren duiken van de hoge plank.","De eerste keer durfde hij niet en liep terug.","Beneden moedigde zijn juf hem aan.","De tweede keer ging hij op de rand staan.","Zijn benen trilden, maar hij bleef staan.","Hij telde zachtjes tot drie.","Toen sprong hij eindelijk naar beneden.","Met een grote plons kwam hij in het water.","Trots klom hij meteen weer de trap op.","Wie zijn angst overwint, kan meer dan hij dacht."], highlightedIndex:9, correctLabel:"hoofdzaak", uitleg:"De slotzin geeft de boodschap van het hele verhaal."},
  {id:96, onderwerp:"media", zinnen:["Op internet kun je bijna alles opzoeken wat je wilt weten.","Je typt een vraag en krijgt meteen veel antwoorden.","Maar niet elk antwoord klopt zomaar.","Iedereen mag namelijk iets op internet zetten.","Daarom kijk je van wie de informatie komt.","Een site van een museum is vaak betrouwbaar.","Twee bronnen vergelijken is altijd slim.","Zeggen ze hetzelfde, dan klopt het meestal.","Zo leer je het echte van het onware te scheiden.","Internet is handig als je het verstandig gebruikt."], highlightedIndex:0, correctLabel:"hoofdzaak", uitleg:"Deze openingszin geeft de hoofdgedachte van de tekst."},
  {id:97, onderwerp:"verhaal", zinnen:["Tom was na school zijn huissleutel kwijt.","Hij zocht in al zijn zakken, maar vond niks.","Zijn vriendje Lars hielp meteen mee zoeken.","Samen liepen ze het hele schoolplein nog eens af.","Bij de schommel lag de sleutel in het zand.","Tom slaakte een zucht van opluchting.","Zonder Lars had hij hem vast nooit gevonden.","Samen zoeken gaat nu eenmaal sneller.","Soms heb je gewoon iemand anders even nodig.","Tom beloofde Lars de volgende keer ook te helpen."], highlightedIndex:4, correctLabel:"detail", uitleg:"Dit is een gebeurtenis in het verhaal, geen kern."},
  {id:98, onderwerp:"natuur", zinnen:["Een koraalrif lijkt op een kleurig bos onder water.","Toch is koraal geen plant, maar bestaat het uit diertjes.","Die diertjes zijn piepklein en leven dicht bij elkaar.","Samen bouwen ze een hard rif van kalk.","Tussen het koraal wonen heel veel vissen.","Ze vinden er eten en een schuilplek.","Een rif groeit maar heel langzaam.","Warm of vuil water kan koraal ziek maken.","Dan verliest het zijn mooie kleuren.","Een koraalrif is een druk thuis voor talloze zeedieren."], highlightedIndex:9, correctLabel:"hoofdzaak", uitleg:"De slotzin vat de hoofdgedachte samen."},
  {id:99, onderwerp:"rekenen", zinnen:["Een breuk laat zien hoeveel deel je van iets hebt.","Het onderste getal telt in hoeveel stukjes iets is verdeeld.","Het bovenste getal zegt hoeveel je daarvan pakt.","Bij een halve pizza heb je één van de twee stukken.","Dat schrijf je op als een half.","Twee kwarten zijn samen ook een half.","Zo kun je dezelfde hoeveelheid anders opschrijven.","Een groter onderaantal betekent kleinere stukjes.","Breuken kom je vaak tegen bij koken en delen.","Daarom is het handig om ze goed te snappen."], highlightedIndex:3, correctLabel:"detail", uitleg:"Dit is een concreet voorbeeld, geen kern."},
  {id:100, onderwerp:"natuur", zinnen:["Schillen en etensresten hoeven niet altijd in de afvalbak.","Je kunt er ook compost van maken.","Compost is verteerd afval dat op aarde lijkt.","In een composthoop doen kleine beestjes het werk.","Wormen en insecten eten de resten op.","Langzaam wordt het bruine, kruimelige grond.","Die grond is juist heel goed voor planten.","Zo geef je tuinafval een tweede leven.","En je gooit veel minder zomaar weg.","Composteren laat zien dat afval ook waardevol kan zijn."], highlightedIndex:9, correctLabel:"hoofdzaak", uitleg:"De slotzin vat de hoofdgedachte samen."}
];
